import "dart:io"; import "package:image/image.dart" as img; void main() { final bytes = File("assets/footer2.png").readAsBytesSync(); final image = img.decodeImage(bytes); if (image != null) { final pixel = image.getPixel(10, 10); print("Color: #${pixel.r.toRadixString(16).padLeft(2, \"0\")}${pixel.g.toRadixString(16).padLeft(2, \"0\")}${pixel.b.toRadixString(16).padLeft(2, \"0\")}"); } else { print("Failed to decode"); } }
